// implement DATA: Budget Categories
type BudgetCategory struct {
    Name        string  `json:"name"`
    Balance     float64 `json:"balance"`
    MonthlyLimit float64 `json:"monthly_limit"`
}

var budgetCategories []BudgetCategory

func AddCategory(name string, balance float64, monthlyLimit float64) {
    budgetCategories = append(budgetCategories, BudgetCategory{Name: name, Balance: balance, MonthlyLimit: monthlyLimit})
}

func UpdateCategoryBalance(name string, balance float64) {
    for i, category := range budgetCategories {
        if category.Name == name {
            budgetCategories[i].Balance = balance
            break
        }
    }
}

func EnsureCategoryLimits() {
    for i, category := range budgetCategories {
        if category.Balance > category.MonthlyLimit {
            budgetCategories[i].Balance = category.MonthlyLimit
        }
    }
}

